        self.tweet_counts = {}

    def recordTweet(self, tweetName: str, time: int) -> None:
        if tweetName not in self.tweet_counts:
            self.tweet_counts[tweetName] = {}
        self.tweet_counts[tweetName][time] = self.tweet_counts.get(tweetName, {}) .get(time, 0) + 1

    def getTweetCountsPerFrequency(self, freq: str, tweetName: str, startTime: int, endTime: int) -> List[int]:
        if tweetName not in self.tweet_counts:
            return []
        counts = [0] * ( (endTime - startTime) // (60 if freq == "minute" else 3600 if freq == "hour" else 86400) + 1)
        for t in self.tweet_counts[tweetName]:
            if startTime <= t <= endTime:
                index = (t - startTime) // (60 if freq == "minute" else 3600 if freq == "hour" else 86400)
                counts[index] += 1
        return counts
